// Extract company slug and person info from LinkedIn URL
// Expected LinkedIn URL formats:
//   https://www.linkedin.com/in/john-doe-123abc/
//   https://linkedin.com/in/john-doe/
const items = $input.all();
const results = [];

for (const item of items) {
  const row = item.json;
  const linkedinUrl = (row['LinkedIn URL'] || row['LinkedIn url'] || row['linkedin_url'] || '').trim();
  const name = (row['Name'] || row['name'] || '').trim();
  const company = (row['Company'] || row['company'] || '').trim();
  const title = (row['Title'] || row['title'] || '').trim();
  // Extract LinkedIn slug
  let linkedinSlug = '';
  const slugMatch = linkedinUrl.match(/linkedin\.com\/in\/([^/?]+)/);
  if (slugMatch) {
    linkedinSlug = slugMatch[1].replace(/\/$/, '');
  }

  // Parse first/last name
  const nameParts = name.split(/\s+/);
  const firstName = nameParts[0] || '';
  const lastName = nameParts.slice(1).join(' ') || '';

  // Row number for writing back (Google Sheets is 1-indexed, +1 for header)
  // n8n returns rows with a __rowIndex or we track position
  const rowIndex = item.json['__rowIndex'] || item.json['row_number'] || 0;

  results.push({
    json: {
      original_row: row,
      row_index: rowIndex,
      name: name,
      first_name: firstName,
      last_name: lastName,
      linkedin_url: linkedinUrl,
      linkedin_slug: linkedinSlug,
      company: company,
      title: title
    }
  });
}

return results;

// Score lead on employee count, revenue, and title (max 13 pts)
const lead = $('Loop Over Leads').first().json;
const apollo = $input.first().json;

const person = apollo.person || {};
const apolloFailed = !apollo.person;
const org = person.organization || {};

const employeeCount = org.estimated_num_employees || org.employee_count || 0;
let revenue = 0;
const rawRevenue = org.annual_revenue || org.estimated_annual_revenue || 0;
if (typeof rawRevenue === 'string') {
  revenue = parseInt(rawRevenue.replace(/[^0-9]/g, ''), 10) || 0;
} else {
  revenue = Number(rawRevenue) || 0;
}
const revenueStr = org.annual_revenue_printed || '';
const companyName = org.name || lead.company || '';
const personTitle = person.title || lead.title || '';
const seniority = person.seniority || '';

// ============ SCORING ALGORITHM (max 13 pts) ============
let score = 0;
let scoreBreakdown = [];

if (apolloFailed) {
  scoreBreakdown.push('Apollo enrichment failed');
}

// 1. Employee Count (max 5 pts)
if (employeeCount >= 50 && employeeCount <= 200) {
  score += 5;
  scoreBreakdown.push('Employees 50-200: +5');
} else if (employeeCount >= 20 && employeeCount < 50) {
  score += 4;
  scoreBreakdown.push('Employees 20-49: +4');
} else if (employeeCount >= 10 && employeeCount < 20) {
  score += 3;
  scoreBreakdown.push('Employees 10-19: +3');
} else if (employeeCount > 200) {
  score += 3;
  scoreBreakdown.push('Employees 200+: +3');
} else if (employeeCount >= 5 && employeeCount < 10) {
  score += 2;
  scoreBreakdown.push('Employees 5-9 (below ICP): +2');
} else if (employeeCount > 0) {
  score += 1;
  scoreBreakdown.push('Employees <5 (well below ICP): +1');
} else {
  scoreBreakdown.push('Employees unknown: +0');
}

// 2. Revenue (max 5 pts)
if (revenue >= 10000000) {
  score += 5;
  scoreBreakdown.push('Revenue $10M+: +5');
} else if (revenue >= 5000000) {
  score += 4;
  scoreBreakdown.push('Revenue $5-10M: +4');
} else if (revenue >= 1000000) {
  score += 3;
  scoreBreakdown.push('Revenue $1-5M: +3');
} else if (revenue > 0) {
  score += 1;
  scoreBreakdown.push('Revenue <$1M: +1');
} else {
  scoreBreakdown.push('Revenue unknown: +0');
}

// 3. Title / Seniority (max 3 pts)
const titleLower = personTitle.toLowerCase();
const seniorityLower = seniority.toLowerCase();
if (titleLower.includes('ceo') || titleLower.includes('founder') || titleLower.includes('owner') || seniorityLower === 'founder') {
  score += 3;
  scoreBreakdown.push('CEO/Founder/Owner: +3');
} else if (titleLower.includes('coo') || titleLower.includes('president') || titleLower.includes('vp') || titleLower.includes('vice president') || seniorityLower === 'c_suite') {
  score += 2;
  scoreBreakdown.push('COO/President/VP: +2');
} else if (titleLower.includes('director') || titleLower.includes('head of') || seniorityLower === 'director') {
  score += 1;
  scoreBreakdown.push('Director/Head: +1');
} else if (personTitle) {
  scoreBreakdown.push('Other title: +0');
} else {
  scoreBreakdown.push('Title unknown: +0');
}

// ============ FLAGS ============
const flags = [];
if (employeeCount > 0 && employeeCount < 10) {
  flags.push('BELOW ICP: ' + employeeCount + ' employees');
}
if (apolloFailed) {
  flags.push('APOLLO FAILED');
}

// ============ TIER ASSIGNMENT (max 13 pts) ============
let tier = '';
let outreachType = '';
if (score >= 10) {
  tier = 'Tier 1';
  outreachType = 'Loom Video (Priority)';
} else if (score >= 7) {
  tier = 'Tier 2';
  outreachType = 'Loom Video';
} else if (score >= 4) {
  tier = 'Tier 3';
  outreachType = 'Personalized Text';
} else {
  tier = 'Tier 4';
  outreachType = 'Template Outreach';
}

return [{
  json: {
    name: lead.name,
    first_name: lead.first_name,
    last_name: lead.last_name,
    linkedin_url: lead.linkedin_url,
    row_index: lead.row_index,
    company_name: companyName,
    person_title: personTitle,
    employee_count: employeeCount,
    annual_revenue: revenue,
    revenue_display: revenueStr || (revenue ? '$' + (revenue / 1000000).toFixed(1) + 'M' : 'Unknown'),
    score: score,
    max_score: 13,
    tier: tier,
    outreach_type: outreachType,
    score_breakdown: scoreBreakdown.join(' | '),
    flags: flags.join(' | '),
    apollo_failed: apolloFailed
  }
}];

// Build scoring summary from accumulated results
const allScored = $('Score & Tier Lead').all();

let tier1 = 0;
let tier2 = 0;
let tier3 = 0;
let tier4 = 0;
let unscored = 0;
let belowICP = 0;
let totalScore = 0;
let topLeads = [];

for (const item of allScored) {
  const lead = item.json;
  totalScore += lead.score;
  if (lead.employee_count > 0 && lead.employee_count < 10) {
    belowICP++;
  }
  topLeads.push({ name: lead.name, score: lead.score, tier: lead.tier, company: lead.company_name || '?', employees: lead.employee_count || '?' });

  switch(lead.tier) {
    case 'Tier 1': tier1++; break;
    case 'Tier 2': tier2++; break;
    case 'Tier 3': tier3++; break;
    case 'Tier 4': tier4++; break;
    default: unscored++; break;
  }
}

const total = allScored.length;
const avgScore = total > 0 ? (totalScore / total).toFixed(1) : 0;

topLeads.sort((a, b) => b.score - a.score);
const top10 = topLeads.slice(0, 10)
  .map((l, i) => {
    const parts = l.name.split(' ');
    const display = parts[0] + (parts[1] ? ' ' + parts[1][0] + '.' : '');
    const flag = (typeof l.employees === 'number' && l.employees > 0 && l.employees < 10) ? ' :small_orange_diamond:' : '';
    return `${i + 1}. ${display} — *${l.score}/13* (${l.tier}) — ${l.employees} employees${flag}`;
  })
  .join('\n');

const loomCount = tier1 + tier2;
const loomMinutes = loomCount * 3;
const loomHours = (loomMinutes / 60).toFixed(1);

const summary = `:bar_chart: *Lead Scoring Complete*\n\n` +
  `*${total} leads scored* | Avg score: ${avgScore}/13\n\n` +
  `:fire: *Tier 1 — Loom Priority* (10-13): ${tier1} leads\n` +
  `:movie_camera: *Tier 2 — Loom Video* (7-9): ${tier2} leads\n` +
  `:memo: *Tier 3 — Personalized Text* (4-6): ${tier3} leads\n` +
  `:envelope: *Tier 4 — Template* (0-3): ${tier4} leads\n` +
  (unscored > 0 ? `:warning: *Unscored (Apollo failed):* ${unscored} leads — review in sheet\n` : '') +
  (belowICP > 0 ? `:small_orange_diamond: *Below ICP (<10 employees):* ${belowICP} leads — check Flags column\n` : '') +
  `\n:clock3: *Estimated Loom time:* ${loomCount} videos × 3 min = *${loomHours} hours*\n\n` +
  `---\n:trophy: *Top 10:*\n${top10}\n\n_Full details in the Google Sheet._`;

return [{ json: { summary, total, tier1_count: tier1, tier2_count: tier2, tier3_count: tier3, tier4_count: tier4, unscored_count: unscored, below_icp_count: belowICP, loom_count: loomCount, loom_hours: loomHours } }];

// Fallback when Apollo fails — score title from sheet data if available
const lead = $('Loop Over Leads').first().json;

let score = 0;
let scoreBreakdown = ['Apollo enrichment failed — scoring title from sheet only'];

const titleLower = (lead.title || '').toLowerCase();
if (titleLower.includes('ceo') || titleLower.includes('founder') || titleLower.includes('owner')) {
  score += 3;
  scoreBreakdown.push('CEO/Founder/Owner (from sheet): +3');
} else if (titleLower.includes('coo') || titleLower.includes('president') || titleLower.includes('vp')) {
  score += 2;
  scoreBreakdown.push('COO/President/VP (from sheet): +2');
} else if (titleLower.includes('director') || titleLower.includes('head of')) {
  score += 1;
  scoreBreakdown.push('Director/Head (from sheet): +1');
}

let tier = 'Unscored';
let outreachType = 'Needs Manual Review';
if (score >= 4) {
  tier = 'Tier 3';
  outreachType = 'Personalized Text';
}

return [{
  json: {
    name: lead.name,
    first_name: lead.first_name,
    last_name: lead.last_name,
    linkedin_url: lead.linkedin_url,
    row_index: lead.row_index,
    company_name: lead.company || '',
    person_title: lead.title || '',
    employee_count: 0,
    annual_revenue: 0,
    revenue_display: 'Unknown',
    score: score,
    max_score: 13,
    tier: tier,
    outreach_type: outreachType,
    score_breakdown: scoreBreakdown.join(' | '),
    apollo_failed: true
  }
}];

// Inline delay to respect Apollo rate limits without breaking splitInBatches loop state
// The Wait node (n8n-nodes-base.wait) suspends execution to a 'waiting' state which
// breaks loop context. This Code node delays inline within the same execution.
const delay = ms => new Promise(resolve => setTimeout(resolve, ms));
await delay(1500);
return $input.all();
